const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const _nativeAddEventListener = EventTarget.prototype.addEventListener;
const safeAddEventListener = (el, type, handler, options) => {
  if (!el) return;
  _nativeAddEventListener.call(el, type, handler, options);
};

const getSoloIdFromUrl = () => {
  try {
    const url = new URL(window.location.href);
    return url.searchParams.get("solo");
  } catch (e) {
    return null;
  }
};

const applySoloMode = () => {
  const soloId = getSoloIdFromUrl();
  if (!soloId) return;
  document.body.dataset.singleSim = "true";
  document.body.classList.add("solo-mode");
  const labs = Array.from(document.querySelectorAll(".lab"));
  if (labs.length === 0) return;
  const target = labs.find((lab) => lab.id === soloId) || document.getElementById(soloId);
  if (!target) return;
  labs.forEach((lab) => {
    if (lab !== target) {
      lab.remove();
    }
  });
  const subtitle = document.querySelector(".site-header .brand-subtitle");
  if (subtitle) {
    subtitle.textContent = "Single Simulation View";
  }
  const nav = document.querySelector(".site-header .nav");
  if (nav) {
    nav.innerHTML = `
      <a href="index.html#experiments">Simulation Library</a>
      <a href="index.html">Home</a>
      <a class="btn primary" href="index.html#tryfree">Try Free</a>
    `;
  }
  const heading = target.querySelector(".lab-header h2");
  if (heading && heading.textContent) {
    document.title = `${heading.textContent} · Physics Experiments Lab`;
  }
  const maybeRemove = [
    ".page-controls",
    ".pagination",
    "[data-page-controls]",
    "[data-pagination]",
    ".hero-card",
    ".favorites",
  ];
  maybeRemove.forEach((selector) => {
    document.querySelectorAll(selector).forEach((el) => el.remove());
  });
  requestAnimationFrame(() => {
    window.dispatchEvent(new Event("resize"));
  });
};

