const wavelengthToRgb = (wavelength) => {
  let r = 0;
  let g = 0;
  let b = 0;

  if (wavelength >= 380 && wavelength < 440) {
    r = -(wavelength - 440) / (440 - 380);
    g = 0;
    b = 1;
  } else if (wavelength >= 440 && wavelength < 490) {
    r = 0;
    g = (wavelength - 440) / (490 - 440);
    b = 1;
  } else if (wavelength >= 490 && wavelength < 510) {
    r = 0;
    g = 1;
    b = -(wavelength - 510) / (510 - 490);
  } else if (wavelength >= 510 && wavelength < 580) {
    r = (wavelength - 510) / (580 - 510);
    g = 1;
    b = 0;
  } else if (wavelength >= 580 && wavelength < 645) {
    r = 1;
    g = -(wavelength - 645) / (645 - 580);
    b = 0;
  } else if (wavelength >= 645 && wavelength <= 750) {
    r = 1;
    g = 0;
    b = 0;
  }

  let factor = 1;
  if (wavelength > 700) {
    factor = 0.3 + 0.7 * (750 - wavelength) / (750 - 700);
  } else if (wavelength < 420) {
    factor = 0.3 + 0.7 * (wavelength - 380) / (420 - 380);
  }

  return {
    r: Math.round(r * 255 * factor),
    g: Math.round(g * 255 * factor),
    b: Math.round(b * 255 * factor),
  };
};

const bindRange = (input, output, onChange) => {
  if (!input || !output) {
    return () => {};
  }
  const update = () => {
    if (!input || !output) return;
    output.textContent = input.value;
    if (onChange) {
      onChange();
    }
  };
  safeAddEventListener(input, "input", update);
  update();
  return update;
};

const resizeCanvas = (canvas, ctx) => {
  if (!canvas) return;
  const { dprCap } = getPerfConfig();
  const dpr = Math.min(window.devicePixelRatio || 1, dprCap);
  const rect = canvas.getBoundingClientRect();
  let cssWidth = rect.width || canvas.clientWidth;
  let cssHeight = rect.height || canvas.clientHeight;
  
  // Fallback to offset dimensions if client dimensions are 0
  if (cssWidth === 0) cssWidth = canvas.offsetWidth || 280;
  if (cssHeight === 0) cssHeight = canvas.offsetHeight || 280;
  
  canvas.width = Math.floor(cssWidth * dpr);
  canvas.height = Math.floor(cssHeight * dpr);
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.imageSmoothingEnabled = true;
  if ("imageSmoothingQuality" in ctx) {
    ctx.imageSmoothingQuality = "high";
  }
  ctx.lineCap = "round";
  ctx.lineJoin = "round";
  ctx.miterLimit = 2;
};

const getCanvasSize = (canvas) => {
  if (!canvas) {
    return { width: 0, height: 0 };
  }
  const rect = canvas.getBoundingClientRect();
  let width = rect.width || canvas.clientWidth;
  let height = rect.height || canvas.clientHeight;
  if (width === 0) width = canvas.offsetWidth || 280;
  if (height === 0) height = canvas.offsetHeight || 280;
  return { width, height };
};

const tooltipTimers = new WeakMap();

const showTooltip = (element, message, x, y) => {
  if (!element) {
    return;
  }
  element.textContent = message;
  element.style.left = `${x + 12}px`;
  element.style.top = `${y + 12}px`;
  element.classList.add("show");

  if (tooltipTimers.has(element)) {
    clearTimeout(tooltipTimers.get(element));
  }
  const timer = setTimeout(() => {
    element.classList.remove("show");
  }, 2400);
  tooltipTimers.set(element, timer);
};

const hideTooltip = (element) => {
  if (!element) {
    return;
  }
  element.classList.remove("show");
  if (tooltipTimers.has(element)) {
    clearTimeout(tooltipTimers.get(element));
  }
};

const getCanvasPoint = (canvas, event) => {
  const rect = canvas.getBoundingClientRect();
  return {
    x: event.clientX - rect.left,
    y: event.clientY - rect.top,
  };
};

const distanceToSegment = (px, py, ax, ay, bx, by) => {
  const abx = bx - ax;
  const aby = by - ay;
  const apx = px - ax;
  const apy = py - ay;
  const ab2 = abx * abx + aby * aby;
  const t = ab2 === 0 ? 0 : clamp((apx * abx + apy * aby) / ab2, 0, 1);
  const cx = ax + abx * t;
  const cy = ay + aby * t;
  return Math.hypot(px - cx, py - cy);
};

const getThemeColors = () => {
  const isLight = document.documentElement.getAttribute('data-theme') === 'light';
  return {
    bg: isLight ? '#ffffff' : '#050a10',
    text: isLight ? '#0e141b' : '#f4f7fb',
    textMuted: isLight ? '#5a6577' : '#a7b3c2',
    accent: isLight ? '#2a90c7' : '#69d1ff',
    accent2: isLight ? '#c9870a' : '#f7c873',
    labelBg: isLight ? 'rgba(255, 255, 255, 0.95)' : 'rgba(8, 12, 18, 0.85)',
    labelBorder: isLight ? 'rgba(0, 0, 0, 0.15)' : 'rgba(255, 255, 255, 0.12)',
    grid: isLight ? 'rgba(0, 0, 0, 0.1)' : 'rgba(255, 255, 255, 0.1)',
    axis: isLight ? 'rgba(0, 0, 0, 0.4)' : 'rgba(148, 163, 184, 0.5)',
  };
};

const drawLabel = (ctx, text, x, y, align = "left") => {
  const colors = getThemeColors();
  ctx.save();
  ctx.font = "600 12px \"Inter\", system-ui, \"Space Grotesk\", sans-serif";
  ctx.textBaseline = "top";
  ctx.textAlign = align;
  const metrics = ctx.measureText(text);
  const paddingX = 10;
  const paddingY = 6;
  const width = metrics.width + paddingX * 2;
  const height = 16 + paddingY * 2;
  const left = align === "center" ? x - width / 2 : align === "right" ? x - width : x;
  const top = y;
  const radius = 10;

  const bg = ctx.createLinearGradient(0, top, 0, top + height);
  bg.addColorStop(0, colors.labelBg);
  bg.addColorStop(1, "rgba(0,0,0,0.28)");
  ctx.fillStyle = bg;
  ctx.strokeStyle = colors.labelBorder;
  ctx.lineWidth = 1;
  ctx.shadowColor = "rgba(0,0,0,0.35)";
  ctx.shadowBlur = 10;
  ctx.beginPath();
  if (typeof ctx.roundRect === "function") {
    ctx.roundRect(left, top, width, height, radius);
  } else {
    ctx.rect(left, top, width, height);
  }
  ctx.fill();
  ctx.shadowBlur = 0;
  ctx.stroke();

  ctx.fillStyle = colors.text;
  ctx.shadowColor = "rgba(0,0,0,0.6)";
  ctx.shadowBlur = 6;
  ctx.fillText(text, align === "center" ? x : align === "right" ? x - paddingX : x + paddingX, top + paddingY);
  ctx.restore();
};

let ambientTime = 0;
let smoothDt = 0.016;

const setReadout = (sim, lines) => {
  if (!sim || !sim.canvas) return;
  let readout = sim.readout;
  if (!readout) {
    const wrap = sim.canvas.closest(".canvas-wrap");
    if (wrap) {
      readout = wrap.querySelector(".readout");
      if (!readout) {
        readout = document.createElement("div");
        readout.className = "readout";
        const firstLearning =
          wrap.querySelector(".notice.learning-block") ||
          wrap.querySelector(".questions.learning-block") ||
          wrap.querySelector(".theory.learning-block") ||
          wrap.querySelector(".tools.learning-block");
        if (firstLearning) {
          wrap.insertBefore(readout, firstLearning);
        } else {
          wrap.appendChild(readout);
        }
      }
    }
    sim.readout = readout;
  }
  if (!readout) return;
  readout.innerHTML = "";
  lines.forEach((line) => {
    const chip = document.createElement("span");
    chip.textContent = line;
    readout.appendChild(chip);
  });
};

const canvasReadoutMap = new Map();
let readoutFlushScheduled = false;

const scheduleReadoutFlush = () => {
  if (readoutFlushScheduled) return;
  readoutFlushScheduled = true;
  queueMicrotask(() => {
    readoutFlushScheduled = false;
    canvasReadoutMap.forEach((readout, canvas) => {
      const ctx = canvas.getContext("2d");
      const lines = ctx && ctx.__readoutLines;
      if (lines && lines.length) {
        setReadout({ canvas, readout }, lines);
        ctx.__readoutLines = [];
      }
    });
  });
};

const shouldCaptureReadout = (text, x, y) => {
  if (typeof text !== "string") return false;
  if (x > 180 || y > 140) return false;
  const hasDigit = /\d/.test(text);
  const hasUnit = /[°%]|(m|cm|mm|kg|g|s|A|V|W|J|Pa|N|Hz|K|T|Ω|C|F)\b/.test(text);
  const hasColon = text.includes(":");
  const hasStatus = /floats|sinks|status|neutral/i.test(text);
  return hasColon || hasDigit || hasUnit || hasStatus;
};

if (typeof CanvasRenderingContext2D !== "undefined") {
  const originalFillText = CanvasRenderingContext2D.prototype.fillText;
  CanvasRenderingContext2D.prototype.fillText = function (text, x, y, maxWidth) {
    if (this.__captureReadout && shouldCaptureReadout(text, x, y)) {
      if (!this.__readoutLines) this.__readoutLines = [];
      this.__readoutLines.push(String(text));
      scheduleReadoutFlush();
      return;
    }
    return originalFillText.call(this, text, x, y, maxWidth);
  };
}

const drawCallout = (ctx, text, x, y, targetX, targetY, align = "left") => {
  ctx.save();
  ctx.strokeStyle = "rgba(105, 209, 255, 0.6)";
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(x, y + 12);
  ctx.lineTo(targetX, targetY);
  ctx.stroke();
  drawLabel(ctx, text, x, y, align);
  ctx.restore();
};

const drawArrow = (ctx, x1, y1, x2, y2, color = "rgba(105, 209, 255, 0.9)") => {
  const angle = Math.atan2(y2 - y1, x2 - x1);
  const headLength = 10;
  ctx.save();
  ctx.strokeStyle = color;
  ctx.fillStyle = color;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(x1, y1);
  ctx.lineTo(x2, y2);
  ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(x2, y2);
  ctx.lineTo(x2 - headLength * Math.cos(angle - Math.PI / 6), y2 - headLength * Math.sin(angle - Math.PI / 6));
  ctx.lineTo(x2 - headLength * Math.cos(angle + Math.PI / 6), y2 - headLength * Math.sin(angle + Math.PI / 6));
  ctx.closePath();
  ctx.fill();
  ctx.restore();
};

const RENDER_CACHE = new WeakMap();

const getRenderCache = (ctx) => {
  const canvas = ctx?.canvas;
  if (!canvas) {
    return { sprites: new Map(), overlays: new Map() };
  }
  let cache = RENDER_CACHE.get(canvas);
  if (!cache) {
    cache = { sprites: new Map(), overlays: new Map() };
    RENDER_CACHE.set(canvas, cache);
  }
  return cache;
};

const toTransparent = (color, alpha = 0) => {
  if (color.startsWith("rgba(")) {
    return color.replace(/rgba\\(([^,]+),([^,]+),([^,]+),[^\\)]+\\)/, `rgba($1,$2,$3,${alpha})`);
  }
  if (color.startsWith("rgb(")) {
    return color.replace(/rgb\\(([^,]+),([^,]+),([^\\)]+)\\)/, `rgba($1,$2,$3,${alpha})`);
  }
  if (color.startsWith("#")) {
    const hex = color.replace("#", "");
    const value = hex.length === 3
      ? hex.split("").map((c) => parseInt(c + c, 16))
      : [hex.slice(0, 2), hex.slice(2, 4), hex.slice(4, 6)].map((c) => parseInt(c, 16));
    return `rgba(${value[0]},${value[1]},${value[2]},${alpha})`;
  }
  return color;
};

const getGlowSprite = (ctx, radius, color) => {
  const cache = getRenderCache(ctx);
  const key = `${radius}|${color}`;
  if (cache.sprites.has(key)) {
    return cache.sprites.get(key);
  }
  const size = Math.max(24, Math.ceil(radius * 4));
  const sprite = document.createElement("canvas");
  sprite.width = size;
  sprite.height = size;
  const sctx = sprite.getContext("2d");
  const center = size / 2;
  const grad = sctx.createRadialGradient(center, center, 0, center, center, size / 2);
  grad.addColorStop(0, color);
  grad.addColorStop(0.35, toTransparent(color, 0.55));
  grad.addColorStop(1, toTransparent(color, 0));
  sctx.fillStyle = grad;
  sctx.beginPath();
  sctx.arc(center, center, size / 2, 0, Math.PI * 2);
  sctx.fill();
  cache.sprites.set(key, sprite);
  return sprite;
};

const drawGlowingPoint = (ctx, x, y, radius, color, intensity = 1) => {
  const { perf } = getPerfConfig();
  const adjRadius = perf ? radius * 0.8 : radius;
  const adjIntensity = perf ? intensity * 0.7 : intensity;
  const sprite = getGlowSprite(ctx, adjRadius, color);
  const size = sprite.width;
  ctx.save();
  ctx.globalAlpha = clamp(adjIntensity, 0.1, 1);
  ctx.drawImage(sprite, x - size / 2, y - size / 2, size, size);
  ctx.restore();
};

const drawGradientLine = (ctx, x1, y1, x2, y2, stops, width = 2) => {
  ctx.save();
  const gradient = ctx.createLinearGradient(x1, y1, x2, y2);
  stops.forEach(([offset, color]) => gradient.addColorStop(offset, color));
  ctx.strokeStyle = gradient;
  ctx.lineWidth = width;
  ctx.lineCap = "round";
  ctx.beginPath();
  ctx.moveTo(x1, y1);
  ctx.lineTo(x2, y2);
  ctx.stroke();
  ctx.restore();
};

const drawParticleSprite = (ctx, particle) => {
  drawGlowingPoint(ctx, particle.x, particle.y, particle.r, particle.color, particle.intensity || 0.9);
};

class Renderer {
  constructor(canvas, ctx) {
    this.canvas = canvas;
    this.ctx = ctx;
    this.cache = getRenderCache(ctx);
  }

  resize() {
    resizeCanvas(this.canvas, this.ctx);
  }

  size() {
    return getCanvasSize(this.canvas);
  }

  glowPoint(x, y, radius, color, intensity) {
    drawGlowingPoint(this.ctx, x, y, radius, color, intensity);
  }

  gradientLine(x1, y1, x2, y2, stops, width) {
    drawGradientLine(this.ctx, x1, y1, x2, y2, stops, width);
  }

  polish(accent) {
    const { width, height } = this.size();
    drawCanvasPolish(this.ctx, width, height, accent);
  }
}

const drawAmbientParticles = (ctx, width, height, now, color = "rgba(106, 215, 255, 0.35)", count = 24) => {
  const perfCfg = getPerfConfig();
  if (perfCfg.perf) return;
  ctx.save();
  ctx.globalCompositeOperation = "lighter";
  ctx.globalAlpha = 0.35;
  const scale = perfCfg.particleScale;
  const actualCount = Math.max(4, Math.round(count * scale));
  for (let i = 0; i < actualCount; i += 1) {
    const seed = i * 97.3;
    const t = now * 0.15 + seed;
    const x = (Math.sin(t) * 0.5 + 0.5) * width;
    const y = (Math.cos(t * 0.8 + seed) * 0.5 + 0.5) * height;
    const r = (2 + (Math.sin(seed * 0.7) * 0.5 + 0.5) * 4) * scale;
    drawGlowingPoint(ctx, x, y, r, color, 0.65);
  }
  ctx.restore();
};

const drawWaterShimmer = (ctx, x, y, w, t, color = "rgba(170, 230, 255, 0.5)") => {
  ctx.save();
  ctx.strokeStyle = color;
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  const amp = 3;
  for (let i = 0; i <= 30; i += 1) {
    const px = x + (i / 30) * w;
    const py = y + Math.sin(t * 2 + i * 0.6) * amp;
    if (i === 0) ctx.moveTo(px, py);
    else ctx.lineTo(px, py);
  }
  ctx.stroke();
  ctx.restore();
};

const drawSignatureGlow = (ctx, x, y, radius, color) => {
  drawGlowingPoint(ctx, x, y, radius, color, 0.9);
};

const SIM_ACCENTS = [
  "rgba(106, 215, 255, 0.18)",
  "rgba(247, 200, 115, 0.18)",
  "rgba(140, 232, 186, 0.16)",
  "rgba(181, 146, 255, 0.16)",
  "rgba(255, 160, 140, 0.15)",
];

const getSimAccent = (id) => {
  if (!id) return SIM_ACCENTS[0];
  let hash = 0;
  for (let i = 0; i < id.length; i += 1) {
    hash = (hash * 31 + id.charCodeAt(i)) % 997;
  }
  return SIM_ACCENTS[Math.abs(hash) % SIM_ACCENTS.length];
};

const drawCanvasPolish = (ctx, width, height, accent) => {
  const perfCfg = getPerfConfig();
  if (perfCfg.perf || perfCfg.mobile) {
    ctx.save();
    ctx.strokeStyle = "rgba(255, 255, 255, 0.06)";
    ctx.lineWidth = 1;
    ctx.strokeRect(4, 4, width - 8, height - 8);
    ctx.restore();
    return;
  }
  const cache = getRenderCache(ctx);
  const key = `${width}x${height}|${accent}`;
  let overlay = cache.overlays.get(key);
  if (!overlay) {
    overlay = document.createElement("canvas");
    overlay.width = width;
    overlay.height = height;
    const octx = overlay.getContext("2d");

    const glow = octx.createRadialGradient(
      width * 0.78,
      height * 0.18,
      0,
      width * 0.78,
      height * 0.18,
      Math.max(width, height) * 0.9
    );
    glow.addColorStop(0, accent);
    glow.addColorStop(0.6, "rgba(0,0,0,0)");
    octx.fillStyle = glow;
    octx.globalAlpha = 0.9;
    octx.fillRect(0, 0, width, height);

    const streak = octx.createLinearGradient(0, 0, width, height);
    streak.addColorStop(0, "rgba(255, 255, 255, 0.08)");
    streak.addColorStop(0.35, "rgba(255, 255, 255, 0)");
    streak.addColorStop(0.7, "rgba(255, 255, 255, 0.06)");
    octx.globalAlpha = 0.7;
    octx.fillStyle = streak;
    octx.fillRect(0, 0, width, height);

    const vignette = octx.createRadialGradient(
      width * 0.5,
      height * 0.5,
      Math.min(width, height) * 0.15,
      width * 0.5,
      height * 0.5,
      Math.max(width, height) * 0.95
    );
    vignette.addColorStop(0, "rgba(0,0,0,0)");
    vignette.addColorStop(1, "rgba(0,0,0,0.35)");
    octx.globalAlpha = 1;
    octx.fillStyle = vignette;
    octx.fillRect(0, 0, width, height);

    octx.strokeStyle = "rgba(255, 255, 255, 0.09)";
    octx.lineWidth = 1.2;
    const inset = 5;
    if (typeof octx.roundRect === "function") {
      octx.beginPath();
      octx.roundRect(inset, inset, width - inset * 2, height - inset * 2, 12);
      octx.stroke();
    } else {
      octx.strokeRect(inset, inset, width - inset * 2, height - inset * 2);
    }

    cache.overlays.set(key, overlay);
  }
  ctx.save();
  ctx.drawImage(overlay, 0, 0);
  ctx.restore();
};

const applyPolishToSim = (sim) => {
  if (!sim || sim._polishApplied || typeof sim.draw !== "function") return;
  const originalDraw = sim.draw;
  sim.draw = (...args) => {
    originalDraw(...args);
    const ctx = sim.ctx || sim.canvas?.getContext("2d");
    if (!ctx || !sim.canvas) return;
    if (!sim.renderer) {
      sim.renderer = new Renderer(sim.canvas, ctx);
    }
    const { width, height } = sim.renderer.size();
    sim.renderer.polish(getSimAccent(sim.id));
    if (typeof sim.overlayDraw === "function") {
      sim.overlayDraw(ctx, width, height);
    }
  };
  sim._polishApplied = true;
};

