let allSims = [];

const attachDraw = (sim, drawFn) => {
  if (!sim || typeof drawFn !== "function") return;
  if (!sim.draw) {
    sim.draw = drawFn;
  }
  if (!sim._checkboxBound && sim.controls) {
    Object.values(sim.controls).forEach((input) => {
      if (input && input.type === "checkbox") {
        safeAddEventListener(input, "change", drawFn);
      }
    });
    sim._checkboxBound = true;
  }
};

const attachDrawByName = (sim, fnName) => {
  const fn = typeof fnName === "string" ? globalThis[fnName] : null;
  if (typeof fn === "function") {
    attachDraw(sim, fn);
  }
};

let registerSimsLater = () => {};

const simByCanvas = new Map();
const activeSims = new Set();

const ensureSimDraw = (sim) => {
  if (!sim || !sim.canvas || typeof sim.draw !== "function") return;
  resizeCanvas(sim.canvas, sim.ctx);
  if (!getPerfConfig().perf || !sim._drawOnce) {
    sim.draw();
    if (getPerfConfig().perf) sim._drawOnce = true;
  }
  sim._lazyInitialized = true;
};

const activateSection = (section) => {
  if (!section) return;
  const canvases = section.querySelectorAll("canvas.lab-canvas");
  const perfCfg = getPerfConfig();
  const list = perfCfg.perf || perfCfg.mobile ? Array.from(canvases).slice(0, 1) : Array.from(canvases);
  list.forEach((canvas) => {
    const sim = simByCanvas.get(canvas);
    if (!sim) return;
    activeSims.add(sim);
    ensureSimDraw(sim);
  });
};

const initLazySims = () => {
  allSims.forEach((sim) => {
    if (sim && sim.canvas) {
      simByCanvas.set(sim.canvas, sim);
    }
  });
  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          activateSection(entry.target);
        } else {
          const canvases = entry.target.querySelectorAll("canvas.lab-canvas");
          canvases.forEach((canvas) => {
            const sim = simByCanvas.get(canvas);
            if (sim) {
              activeSims.delete(sim);
            }
          });
        }
      });
    },
    { rootMargin: "200px 0px" }
  );
  document.querySelectorAll(".lab").forEach((section) => observer.observe(section));
  document.querySelectorAll(".lab").forEach((section) => {
    if (isElementInViewport(section)) {
      activateSection(section);
    }
  });
};

const drawAxes = (ctx, rect, xLabel, yLabel) => {
  const colors = getThemeColors();
  const pad = 30;
  const origin = { x: rect.x + pad, y: rect.y + rect.h - pad };
  const width = rect.w - pad * 1.6;
  const height = rect.h - pad * 1.6;
  ctx.save();
  ctx.strokeStyle = colors.axis;
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(origin.x, origin.y);
  ctx.lineTo(origin.x + width, origin.y);
  ctx.moveTo(origin.x, origin.y);
  ctx.lineTo(origin.x, origin.y - height);
  ctx.stroke();
  if (xLabel) {
    drawLabel(ctx, xLabel, origin.x + width - 8, origin.y + 8, "right");
  }
  if (yLabel) {
    drawLabel(ctx, yLabel, origin.x - 6, rect.y + 4, "left");
  }
  ctx.restore();
  return { origin, width, height, pad };
};

const bindTeacherToggle = (toggle, panel, learningToggle) => {
  if (!toggle || !panel) {
    return;
  }
  const update = () => {
    applyTeacherVisibility(toggle, panel, learningToggle);
  };
  if (!toggle.dataset.bound) {
    safeAddEventListener(toggle, "change", update);
    toggle.dataset.bound = "true";
  }
  update();
};

const applyTeacherVisibility = (toggle, panel) => {
  if (!toggle || !panel) {
    return;
  }
  panel.classList.toggle("show", toggle.checked);
};

const updateLearningVisibility = (toggle, group) => {
  if (!toggle) {
    return;
  }
  const show = toggle.checked;
  const blocks = document.querySelectorAll(`.learning-block[data-group="${group}"]`);
  blocks.forEach((block) => {
    block.classList.toggle("hidden", !show);
  });
  if (typeof syncGlobalLearningToggle === "function") {
    syncGlobalLearningToggle();
  }
};

const bindLearningToggle = (toggle, group) => {
  if (!toggle) {
    return;
  }
  const update = () => updateLearningVisibility(toggle, group);
  if (!toggle.dataset.bound) {
    safeAddEventListener(toggle, "change", update);
    toggle.dataset.bound = "true";
  }
  update();
};

const normalizeLearningPanels = () => {
  const labs = Array.from(document.querySelectorAll(".lab"));
  labs.forEach((lab) => {
    const labId = lab.id || "lab";
    const title = lab.querySelector(".lab-header h2")?.textContent?.trim() || "This experiment";
    const grid = lab.querySelector(".lab-grid");
    const controls = lab.querySelector(".controls");
    const canvasWrap = lab.querySelector(".canvas-wrap");
    const existingBlocks = Array.from(lab.querySelectorAll(".learning-block"));
    let group = existingBlocks.find((block) => block.dataset.group)?.dataset.group || labId;

    let learningPanels = lab.querySelector(".learning-panels");
    if (!learningPanels) {
      learningPanels = document.createElement("div");
      learningPanels.className = "learning-panels";
      if (canvasWrap && canvasWrap.parentNode === grid) {
        grid.appendChild(learningPanels);
      } else if (grid) {
        grid.appendChild(learningPanels);
      }
    }

    existingBlocks.forEach((block) => {
      block.dataset.group = group;
      const hasType = ["notice", "questions", "theory", "tools"].some((cls) => block.classList.contains(cls));
      if (!hasType) {
        block.classList.add("theory");
      }
      if (!block.querySelector("h4") && block.classList.contains("theory")) {
        block.insertAdjacentHTML("afterbegin", "<h4>Short theory</h4>");
      }
      if (block.parentNode !== learningPanels) {
        learningPanels.appendChild(block);
      }
    });

    const parentForBlocks = learningPanels;



    const ensureBlock = (type, titleText, innerHtml) => {
      if (!lab.querySelector(`.${type}.learning-block`)) {
        const block = document.createElement("div");
        block.className = `${type} learning-block`;
        block.dataset.group = group;
        block.innerHTML = `<h4>${titleText}</h4>${innerHtml}`;
        parentForBlocks.appendChild(block);
      }
    };

    ensureBlock(
      "notice",
      "What to notice",
      `<p>Use the controls to vary the inputs and observe how the output responds in ${title}.</p>`
    );
    ensureBlock(
      "questions",
      "Guided questions",
      `<ol>
        <li>Which control causes the largest change in the result?</li>
        <li>Does the output change linearly as you increase the main input?</li>
        <li>What settings give the maximum or minimum output?</li>
      </ol>`
    );
    ensureBlock(
      "theory",
      "Short theory",
      `<p>This simulation lets you explore the relationship between the main variables in ${title}.</p>
      <div class="formula">Record the relationship you observe and compare it with your syllabus formula.</div>`
    );
    ensureBlock(
      "tools",
      "Tools used",
      `<ul>
        <li>Apparatus or model shown in the simulation</li>
        <li>Measurement scale or sensor readout</li>
        <li>Data table or graph for analysis</li>
      </ul>`
    );
    let teacherPanel = lab.querySelector(".teacher-panel");
    if (!teacherPanel) {
      teacherPanel = document.createElement("div");
      teacherPanel.className = "teacher-panel";
      teacherPanel.id = `${labId}TeacherPanel`;
      teacherPanel.innerHTML = `<h4>Teacher mode: 3-step demo</h4>
        <ol>
          <li>Start with default values and ask students to describe the baseline behavior.</li>
          <li>Change one variable at a time and identify the trend.</li>
          <li>Summarize the relationship and connect it to the lesson objective.</li>
        </ol>`;
      parentForBlocks.appendChild(teacherPanel);
    } else if (!teacherPanel.id) {
      teacherPanel.id = `${labId}TeacherPanel`;
    }

    const orderedNodes = [
      ...[
        ".notice.learning-block",
        ".questions.learning-block",
        ".theory.learning-block",
        ".tools.learning-block",
      ]
        .map((selector) => Array.from(lab.querySelectorAll(selector)))
        .flat(),
      ...Array.from(lab.querySelectorAll(".teacher-panel")),
    ].filter(Boolean);
    orderedNodes.forEach((node) => {
      if (node.parentNode !== parentForBlocks) {
        parentForBlocks.appendChild(node);
      }
    });

    let readout = lab.querySelector(".readout");
    if (!readout) {
      readout = document.createElement("div");
      readout.className = "readout";
    }
    const canvas = lab.querySelector("canvas.lab-canvas");
    if (canvas && readout) {
      const ctx = canvas.getContext("2d");
      if (ctx) {
        ctx.__captureReadout = true;
      }
      canvasReadoutMap.set(canvas, readout);
    }

    if (controls) {
      const toggleLabels = Array.from(controls.querySelectorAll("label.toggle"));
      const findToggleByText = (text) =>
        toggleLabels.find((label) => label.textContent.toLowerCase().includes(text));

      let learningToggle = findToggleByText("learning panels")?.querySelector("input[type=\"checkbox\"]");
      if (!learningToggle) {
        const wrapper = document.createElement("label");
        wrapper.className = "toggle";
        wrapper.innerHTML = `<input type="checkbox" id="${labId}Learning" checked />
          <span>Show learning panels</span>`;
        controls.appendChild(wrapper);
        learningToggle = wrapper.querySelector("input");
      }
      learningToggle.dataset.learningGroup = group;

      let teacherToggle = findToggleByText("teacher mode")?.querySelector("input[type=\"checkbox\"]");
      if (!teacherToggle) {
        const wrapper = document.createElement("label");
        wrapper.className = "toggle";
        wrapper.innerHTML = `<input type="checkbox" id="${labId}Teacher" />
          <span>Teacher mode</span>`;
        controls.appendChild(wrapper);
        teacherToggle = wrapper.querySelector("input");
      }
      teacherToggle.dataset.teacherPanel = teacherPanel.id;

      let focusToggle = findToggleByText("focus mode")?.querySelector("input[type=\"checkbox\"]");
      if (!focusToggle) {
        const wrapper = document.createElement("label");
        wrapper.className = "toggle";
        wrapper.innerHTML = `<input type="checkbox" id="${labId}Focus" />
          <span>Focus mode</span>`;
        controls.appendChild(wrapper);
        focusToggle = wrapper.querySelector("input");
      }
      focusToggle.dataset.focusLab = labId;
      if (!focusToggle.dataset.bound) {
        safeAddEventListener(focusToggle, "change", () => {
          lab.classList.toggle("focus-mode", focusToggle.checked);
          if (learningToggle && focusToggle.checked) {
            learningToggle.checked = false;
            updateLearningVisibility(learningToggle, group);
          }
        });
        focusToggle.dataset.bound = "true";
      }

      if (!lab.querySelector(".focus-exit-btn")) {
        const exitBtn = document.createElement("button");
        exitBtn.type = "button";
        exitBtn.className = "focus-exit-btn";
        exitBtn.textContent = "Exit Focus Mode";
        safeAddEventListener(exitBtn, "click", () => {
          focusToggle.checked = false;
          lab.classList.remove("focus-mode");
        });
        const targetWrap = lab.querySelector(".canvas-wrap") || parentForBlocks;
        if (targetWrap) {
          targetWrap.appendChild(exitBtn);
        }
      }
    }
  });
};



