const formulaUsageHints = {
  ohm: "Use for ohmic conductors when temperature is roughly constant.",
  "ideal-gas": "Use for gases that behave ideally; temperature in kelvin.",
  boyle: "Use when temperature and amount of gas are constant.",
  snell: "Use when light crosses a boundary; angles measured from the normal.",
  refraction: "Use when light crosses a boundary; angles measured from the normal.",
  lens: "Use for thin lenses and paraxial rays.",
  pendulum: "Use for small-angle oscillations.",
  shm: "Use for simple harmonic motion near equilibrium.",
  waves: "Use for steady periodic waves in a uniform medium.",
  motion: "Use for 1D motion with constant acceleration.",
  projectile: "Use for projectile motion with constant g and no air resistance.",
  bernoulli: "Use for steady, incompressible, non-viscous flow along a streamline.",
  pressure: "Use for fluids at rest with constant density.",
  grating: "Use for diffraction maxima at small angles.",
  double: "Use for double-slit interference at small angles.",
};

const formulaAssumptions = {
  ohm: "Material is ohmic; temperature stays roughly constant.",
  "ideal-gas": "Gas is dilute; particle volume and interactions are negligible.",
  boyle: "Temperature is constant (isothermal process).",
  snell: "Interface is smooth; media are uniform and isotropic.",
  refraction: "Interface is smooth; media are uniform and isotropic.",
  lens: "Thin-lens and paraxial (small-angle) approximation.",
  pendulum: "Small-angle approximation (sinθ ≈ θ).",
  shm: "Restoring force proportional to displacement.",
  waves: "Linear waves in a uniform medium.",
  motion: "Constant acceleration, one dimension.",
  projectile: "No air resistance; constant g.",
  bernoulli: "Steady, incompressible, non-viscous flow along a streamline.",
  pressure: "Static fluid, uniform density, constant g.",
  grating: "Far-field diffraction; small angles.",
  double: "Coherent source; small-angle, far-field pattern.",
};

const normalizeFormulaToken = (token) => {
  if (!token) return "";
  const subMap = {
    "₀": "0",
    "₁": "1",
    "₂": "2",
    "₃": "3",
    "₄": "4",
    "₅": "5",
    "₆": "6",
    "₇": "7",
    "₈": "8",
    "₉": "9",
    "ₒ": "o",
    "ₜ": "t",
    "ₙ": "n",
    "ᵢ": "i",
  };
  let base = "";
  let sub = "";
  for (const ch of token) {
    if (subMap[ch]) {
      sub += subMap[ch];
    } else {
      base += ch;
    }
  }
  if (sub) return `${base}_${sub}`;
  return base;
};

const extractFormulaSymbols = (formulaText) => {
  if (!formulaText) return [];
  let text = formulaText.replace(/\s+/g, " ");
  text = text.replace(/sin|cos|tan|log|ln|exp|sqrt/gi, " ");

  const symbols = new Set();
  const tokenMatches = text.match(/[A-Za-zα-ωΑ-ΩΔθλμρσΩπφ](?:[₀-₉ₒₜₙᵢ])*/g) || [];
  tokenMatches.forEach((token) => {
    const normalized = normalizeFormulaToken(token);
    if (normalized) symbols.add(normalized);
  });

  const deltaMatches = text.match(/Δ[A-Za-z]/g) || [];
  deltaMatches.forEach((sym) => symbols.add(sym));

  return Array.from(symbols).filter((s) => s && s !== "");
};

const resolveSymbolMeaning = (symbol, group) => {
  const perGroup = formulaSymbolGlossary.perGroup[group];
  if (perGroup && perGroup[symbol]) return perGroup[symbol];
  return formulaSymbolGlossary.common[symbol];
};

const resolveUsageHint = (formulaText, group) => {
  if (formulaUsageHints[group]) return formulaUsageHints[group];
  const compact = (formulaText || "").replace(/\s+/g, "");
  if (compact.includes("v=f") && compact.includes("λ")) {
    return "Use for periodic waves in a uniform medium.";
  }
  if (compact.includes("s=ut") || compact.includes("v=u+at") || compact.includes("=1/2at") || compact.includes("=1/2at^2")) {
    return "Use for motion with constant acceleration in one dimension.";
  }
  if (compact.includes("F=kx")) {
    return "Use within the elastic limit of a spring.";
  }
  if (compact.includes("PV=nRT")) {
    return "Use for ideal gases with temperature in kelvin.";
  }
  if (compact.includes("T=2π")) {
    return "Use for small oscillations around equilibrium.";
  }
  if (compact.includes("I=V/R")) {
    return "Use for ohmic components (linear V–I).";
  }
  if (compact.includes("1/f") || compact.includes("1/f=")) {
    return "Use for thin lenses or mirrors with paraxial rays.";
  }
  if (compact.includes("sin") && compact.includes("n1") && compact.includes("n2")) {
    return "Use when light refracts at an interface; angles to the normal.";
  }
  return "Use when the assumptions in this section apply.";
};

const resolveAssumptions = (formulaText, group) => {
  if (formulaAssumptions[group]) return formulaAssumptions[group];
  const compact = (formulaText || "").replace(/\s+/g, "");
  if (compact.includes("PV=nRT")) return "Ideal gas behavior; temperature in kelvin.";
  if (compact.includes("F=kx")) return "Spring remains within elastic limit.";
  if (compact.includes("T=2π")) return "Small oscillations about equilibrium.";
  if (compact.includes("s=ut") || compact.includes("v=u+at") || compact.includes("=1/2at") || compact.includes("=1/2at^2")) {
    return "Constant acceleration in one dimension.";
  }
  if (compact.includes("I=V/R")) return "Ohmic component with constant resistance.";
  if (compact.includes("1/f") || compact.includes("1/f=")) return "Thin-lens or paraxial approximation.";
  if (compact.includes("sin") && compact.includes("n1") && compact.includes("n2")) {
    return "Angles measured from the normal; media are uniform.";
  }
  return "Assumptions: standard textbook conditions for this model.";
};

const showFormulaToast = (message) => {
  let toast = document.querySelector(".formula-toast");
  if (!toast) {
    toast = document.createElement("div");
    toast.className = "formula-toast";
    document.body.appendChild(toast);
  }
  toast.textContent = message;
  toast.classList.add("show");
  clearTimeout(showFormulaToast._timer);
  showFormulaToast._timer = setTimeout(() => {
    toast.classList.remove("show");
  }, 1400);
};

const copyFormulaText = async (text) => {
  if (!text) return;
  try {
    await navigator.clipboard.writeText(text);
    showFormulaToast("Formula copied");
  } catch (err) {
    const textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.setAttribute("readonly", "");
    textarea.style.position = "absolute";
    textarea.style.left = "-9999px";
    document.body.appendChild(textarea);
    textarea.select();
    try {
      document.execCommand("copy");
      showFormulaToast("Formula copied");
    } finally {
      document.body.removeChild(textarea);
    }
  }
};

const getFormulaGlossary = () => {
  let glossary = document.querySelector(".formula-glossary");
  if (!glossary) {
    glossary = document.createElement("div");
    glossary.className = "formula-glossary";
    document.body.appendChild(glossary);
  }
  return glossary;
};

const showFormulaGlossary = (formulaEl, entries) => {
  if (!entries || entries.length === 0) return;
  const glossary = getFormulaGlossary();
  glossary.innerHTML = `<strong>Symbols</strong><ul>${entries
    .map((entry) => `<li>${entry.symbol} = ${entry.meaning}</li>`)
    .join("")}</ul>`;
  const rect = formulaEl.getBoundingClientRect();
  glossary.style.left = `${rect.left + window.scrollX}px`;
  glossary.style.top = `${rect.bottom + window.scrollY + 8}px`;
  glossary.classList.add("show");
};

const hideFormulaGlossary = () => {
  const glossary = document.querySelector(".formula-glossary");
  if (glossary) glossary.classList.remove("show");
};

const enhanceFormulaExplanations = () => {
  const formulas = Array.from(document.querySelectorAll(".formula"));
  formulas.forEach((formulaEl) => {
    const formulaText = (formulaEl.textContent || "").trim();
    const block = formulaEl.closest(".learning-block");
    const group = block?.dataset?.group || "";
    const parent = formulaEl.parentElement;
    if (!parent) return;
    if (parent.querySelector(".formula-explain")) return;

    if (!formulaEl.querySelector(".formula-copy")) {
      const copyBtn = document.createElement("button");
      copyBtn.type = "button";
      copyBtn.className = "formula-copy";
      copyBtn.setAttribute("aria-label", "Copy formula");
      copyBtn.innerHTML = "Copy";
      safeAddEventListener(copyBtn, "click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        copyFormulaText(formulaText);
      });
      formulaEl.appendChild(copyBtn);
    }

    const usage = resolveUsageHint(formulaText, group);
    const assumptions = resolveAssumptions(formulaText, group);
    const symbols = extractFormulaSymbols(formulaText)
      .map((symbol) => ({ symbol, meaning: resolveSymbolMeaning(symbol, group) }))
      .filter((entry) => entry.meaning);

    if (!formulaEl.dataset.glossaryBound) {
      safeAddEventListener(formulaEl, "mouseenter", () => showFormulaGlossary(formulaEl, symbols));
      safeAddEventListener(formulaEl, "mouseleave", hideFormulaGlossary);
      formulaEl.dataset.glossaryBound = "true";
    }

    const explain = document.createElement("div");
    explain.className = "formula-explain";

    const usageEl = document.createElement("div");
    usageEl.className = "formula-usage";
    usageEl.innerHTML = `<strong>When to use:</strong> ${usage}`;
    explain.appendChild(usageEl);

    const assumptionEl = document.createElement("div");
    assumptionEl.className = "formula-assumptions";
    assumptionEl.innerHTML = `<strong>Assumptions:</strong> ${assumptions}`;
    explain.appendChild(assumptionEl);

    if (symbols.length) {
      const list = document.createElement("ul");
      list.className = "formula-defs";
      symbols.forEach((entry) => {
        const li = document.createElement("li");
        li.textContent = `${entry.symbol} = ${entry.meaning}`;
        list.appendChild(li);
      });
      explain.appendChild(list);
    }

    const note = parent.querySelector(".formula-note");
    if (note && note.nextSibling) {
      note.insertAdjacentElement("afterend", explain);
    } else if (note) {
      note.parentNode.appendChild(explain);
    } else {
      formulaEl.insertAdjacentElement("afterend", explain);
    }
  });
};

normalizeLearningPanels();

