const applyHistoryData = () => {
  const blocks = document.querySelectorAll(".history.learning-block");
  blocks.forEach((block) => {
    const group = block.dataset.group;
    const data = experimentHistory[group];
    if (!data) {
      return;
    }
    block.innerHTML = `
      <h4>Why this experiment matters</h4>
      <p><strong>When:</strong> ${data.when}. <strong>Who:</strong> ${data.who}.</p>
      <p><strong>Problem solved:</strong> ${data.problem}</p>
    `;
  });
};

applyHistoryData();

