const snellMedia = [
  { label: "Air", n: 1.0 },
  { label: "Water", n: 1.33 },
  { label: "Ethanol", n: 1.36 },
  { label: "Acrylic", n: 1.49 },
  { label: "Glass", n: 1.5 },
  { label: "Diamond", n: 2.42 },
];

const getSnellMediumLabel = (value, fallback) => {
  const match = snellMedia.find((m) => Math.abs(m.n - value) < 0.01);
  return match ? match.label : fallback || "Custom";
};

