if (ohm.controls.check) {
  safeAddEventListener(ohm.controls.check, "click", () => {
    if (!ohm.controls.assessment.checked || !ohm.data.assessmentR) return;
    const estimate = parseFloat(ohm.controls.estimate.value);
    if (!Number.isFinite(estimate)) return;
    const target = ohm.data.assessmentR;
    const errorPct = Math.abs(estimate - target) / target * 100;
    if (ohm.controls.checkResult) {
      ohm.controls.checkResult.textContent =
        errorPct <= 5
          ? `Pass (error ${errorPct.toFixed(1)}%)`
          : `Try again (error ${errorPct.toFixed(1)}%)`;
    }
  });
}

safeAddEventListener(ohm.canvas, "click", (event) => {
  const point = getCanvasPoint(ohm.canvas, event);
  const width = ohm.canvas.clientWidth;
  const height = ohm.canvas.clientHeight;
  const voltage = parseFloat(ohm.controls.voltage.value);
  const resistance = parseFloat(ohm.controls.resistance.value);
  const temp = parseFloat(ohm.controls.temp.value);
  const realMeters = ohm.controls.realMeters.checked;
  const component = ohm.controls.component.value;
  const reading = getOhmReading(voltage, resistance, temp, realMeters, component);
  const zeroErr = parseFloat(ohm.controls.zeroErr.value);
  const aRange = parseFloat(ohm.controls.aRange.value);
  const vRange = parseFloat(ohm.controls.vRange.value);
  const meter = getOhmMeterReadings(reading, zeroErr, aRange, vRange);
  const mode = ohm.controls.modeGraph.checked ? "graph" : "circuit";

  let message = "Circuit element.";
  if (mode === "circuit") {
    const layout = getOhmCircuitLayout(width, height);
    const { left, top, bottom, midY } = layout;
    const resistorStart = (layout.right - 90);
    const resistorEnd = (layout.right - 20);
    const ammeterX = (layout.left + layout.right) / 2;
    const voltX = (resistorStart + resistorEnd) / 2;
    const voltY = midY - 60;
    const batteryRect = { x: left - 4, y: top + 10, w: 24, h: 52 };
    const resistorRect = { x: resistorStart - 4, y: midY - 20, w: 80, h: 40 };
    const ammeterRect = { x: ammeterX - 22, y: bottom - 22, w: 44, h: 44 };
    const voltRect = { x: voltX - 20, y: voltY - 20, w: 40, h: 40 };

    if (
      point.x >= batteryRect.x &&
      point.x <= batteryRect.x + batteryRect.w &&
      point.y >= batteryRect.y &&
      point.y <= batteryRect.y + batteryRect.h
    ) {
      message = `Battery: provides ${voltage.toFixed(1)} V.`;
    } else if (
      point.x >= resistorRect.x &&
      point.x <= resistorRect.x + resistorRect.w &&
      point.y >= resistorRect.y &&
      point.y <= resistorRect.y + resistorRect.h
    ) {
      message = `Resistor: ${resistance.toFixed(0)} Ω.`;
    } else if (
      point.x >= ammeterRect.x &&
      point.x <= ammeterRect.x + ammeterRect.w &&
      point.y >= ammeterRect.y &&
      point.y <= ammeterRect.y + ammeterRect.h
    ) {
      message = `Ammeter: current = ${reading.iTotal.toFixed(3)} A.`;
    } else if (
      point.x >= voltRect.x &&
      point.x <= voltRect.x + voltRect.w &&
      point.y >= voltRect.y &&
      point.y <= voltRect.y + voltRect.h
    ) {
      message = `Voltmeter: load voltage = ${reading.vLoad.toFixed(2)} V.`;
    } else if (point.y < top + 6 || point.y > bottom - 6) {
      message = "Wire: carries current through the loop.";
    }
  } else {
    const graph = getOhmGraphLayout(width, height, meter.vMeter, meter.iMeter, 20, Math.max(0.8, 20 / Math.max(4, reading.rTemp)));
    const distanceToPoint = Math.hypot(point.x - graph.xPoint, point.y - graph.yPoint);
    if (distanceToPoint < 10) {
      message = `Data point: (${meter.vMeter.toFixed(2)} V, ${meter.iMeter.toFixed(3)} A).`;
    } else if (point.y > graph.origin.y - 8 && point.y < graph.origin.y + 12) {
      message = "Voltage axis (x-axis).";
    } else if (point.x > graph.origin.x - 12 && point.x < graph.origin.x + 12) {
      message = "Current axis (y-axis).";
    } else {
      message = "V–I relationship (straight line for ohmic conductor).";
    }
  }

  showTooltip(ohm.tooltip, message, point.x, point.y);
});

safeAddEventListener(ohm.canvas, "mouseleave", () => hideTooltip(ohm.tooltip));

