safeAddEventListener(circuits.canvas, "click", (event) => {
  const point = getCanvasPoint(circuits.canvas, event);
  const width = circuits.canvas.clientWidth;
  const height = circuits.canvas.clientHeight;
  const params = getCircuitsParams();
  const mode = params.mode;

  let message = "Circuit element.";
  if (mode === "series") {
    const layout = getSeriesLayout(width, height, params.count);
    const batteryRect = { x: layout.left - 4, y: layout.top + 12, w: 24, h: 58 };
    if (
      point.x >= batteryRect.x &&
      point.x <= batteryRect.x + batteryRect.w &&
      point.y >= batteryRect.y &&
      point.y <= batteryRect.y + batteryRect.h
    ) {
      message = `Battery: ${params.voltage.toFixed(1)} V.`;
    } else {
      const hit = layout.resistors.find(
        (resistor) =>
          point.x >= resistor.x - 6 &&
          point.x <= resistor.x + resistor.w + 6 &&
          point.y >= resistor.y - 18 &&
          point.y <= resistor.y + 18
      );
      if (hit) {
        message = `Resistor ${hit.index}: ${params.resistance.toFixed(0)} Ω (series).`;
      } else {
        message = "Series circuit: current is the same through each resistor.";
      }
    }
  } else {
    const layout = getParallelLayout(width, height, params.count);
    const batteryRect = { x: layout.left - 4, y: layout.top + 6, w: 24, h: 58 };
    if (
      point.x >= batteryRect.x &&
      point.x <= batteryRect.x + batteryRect.w &&
      point.y >= batteryRect.y &&
      point.y <= batteryRect.y + batteryRect.h
    ) {
      message = `Battery: ${params.voltage.toFixed(1)} V.`;
    } else {
      const hit = layout.branches.find(
        (branch) =>
          point.x >= branch.x - 12 &&
          point.x <= branch.x + 12 &&
          point.y >= branch.y1 - 12 &&
          point.y <= branch.y2 + 12
      );
      if (hit) {
        message = `Branch ${hit.index}: ${params.resistance.toFixed(0)} Ω, I = ${params.branchCurrent.toFixed(2)} A.`;
      } else {
        message = "Parallel circuit: voltage is the same across each branch.";
      }
    }
  }

  showTooltip(circuits.tooltip, message, point.x, point.y);
});

safeAddEventListener(circuits.canvas, "mouseleave", () => hideTooltip(circuits.tooltip));

