safeAddEventListener(collisions.canvas, "click", (event) => {
  const point = getCanvasPoint(collisions.canvas, event);
  const layout = collisions.layout;
  let message = "Collision analysis.";
  if (layout) {
    const carts = [layout.before1, layout.before2, layout.after1, layout.after2];
    const hit = carts.find(
      (cart) =>
        point.x >= cart.x &&
        point.x <= cart.x + cart.w &&
        point.y >= cart.y &&
        point.y <= cart.y + cart.h
    );
    if (hit) {
      message = "Trolley mass and velocity.";
    }
  }
  showTooltip(collisions.tooltip, message, point.x, point.y);
});
safeAddEventListener(collisions.canvas, "mouseleave", () => hideTooltip(collisions.tooltip));

