bindRangesToUpdate(snell.controls, updateSnellValues);
safeAddEventListener(snell.controls.labels, "change", drawSnell);
bindLearningToggle(snell.controls.learning, "snell");
bindTeacherToggle(snell.controls.teacher, snell.teacherPanel);
const syncSnellMediumSelect = (value, select) => {
  if (!select) return;
  const match = snellMedia.find((m) => Math.abs(m.n - value) < 0.01);
  select.value = match ? String(match.n) : "custom";
};
if (snell.controls.medium1) {
  safeAddEventListener(snell.controls.medium1, "change", (event) => {
    if (!snell.controls.n1) return;
    const val = event.target.value;
    if (val === "custom") return;
    snell.controls.n1.value = val;
    updateSnellValues();
  });
}
if (snell.controls.medium2) {
  safeAddEventListener(snell.controls.medium2, "change", (event) => {
    if (!snell.controls.n2) return;
    const val = event.target.value;
    if (val === "custom") return;
    snell.controls.n2.value = val;
    updateSnellValues();
  });
}
if (snell.controls.n1) {
  safeAddEventListener(snell.controls.n1, "input", () =>
    syncSnellMediumSelect(parseFloat(snell.controls.n1.value), snell.controls.medium1)
  );
}
if (snell.controls.n2) {
  safeAddEventListener(snell.controls.n2, "input", () =>
    syncSnellMediumSelect(parseFloat(snell.controls.n2.value), snell.controls.medium2)
  );
}
safeAddEventListener(snell.reset, "click", () => {
  Object.entries(snell.defaults).forEach(([key, value]) => {
    if (snell.controls[key]) {
      if (snell.controls[key].type === "checkbox") {
        snell.controls[key].checked = value;
      } else {
        snell.controls[key].value = value;
      }
    }
  });
  updateSnellValues();
  if (snell.controls.n1 && snell.controls.medium1) {
    syncSnellMediumSelect(parseFloat(snell.controls.n1.value), snell.controls.medium1);
  }
  if (snell.controls.n2 && snell.controls.medium2) {
    syncSnellMediumSelect(parseFloat(snell.controls.n2.value), snell.controls.medium2);
  }
  updateLearningVisibility(snell.controls.learning, "snell");
});
safeAddEventListener(snell.canvas, "click", (event) => {
  const point = getCanvasPoint(snell.canvas, event);
  const layout = snell.layout;
  let message = "Refraction at a boundary.";
  if (layout) {
    const distIncident = distanceToSegment(point.x, point.y, layout.incident.x1, layout.incident.y1, layout.incident.x2, layout.incident.y2);
    if (distIncident < 8) {
      message = "Incident ray (θ₁).";
    } else if (layout.refracted) {
      const distRefracted = distanceToSegment(point.x, point.y, layout.refracted.x1, layout.refracted.y1, layout.refracted.x2, layout.refracted.y2);
      if (distRefracted < 8) {
        message = "Refracted ray (θ₂).";
      }
    } else if (layout.reflected) {
      const distReflected = distanceToSegment(point.x, point.y, layout.reflected.x1, layout.reflected.y1, layout.reflected.x2, layout.reflected.y2);
      if (distReflected < 8) {
        message = "Total internal reflection.";
      }
    }
  }
  showTooltip(snell.tooltip, message, point.x, point.y);
});
safeAddEventListener(snell.canvas, "mouseleave", () => hideTooltip(snell.tooltip));

