safeAddEventListener(doubleSlit.canvas, "click", (event) => {
  const point = getCanvasPoint(doubleSlit.canvas, event);
  const width = doubleSlit.canvas.clientWidth;
  const params = getDoubleSlitParams();
  const intensity = getDoubleSlitIntensity(point.x, width, params);
  const centerDistance = Math.abs(point.x - width / 2);
  const region =
    centerDistance < 6 ? "Central maximum (bright fringe)" : "Interference fringe";
  const message = `${region}. Intensity ≈ ${intensity.toFixed(2)}.`;
  showTooltip(doubleSlit.tooltip, message, point.x, point.y);
});

safeAddEventListener(doubleSlit.canvas, "mouseleave", () => hideTooltip(doubleSlit.tooltip));

