Object.entries(radioactive.controls).forEach(([key, input]) => {
  if (radioactive.values[key] && input?.type !== "select-one") {
    bindRange(input, radioactive.values[key], drawRadioactive);
  }
  if (input && input.tagName === "SELECT") {
    safeAddEventListener(input, "change", () => {
      if (radioactive.values.material) {
        const selected = input.options[input.selectedIndex]?.text || input.value;
        radioactive.values.material.textContent = selected;
      }
      drawRadioactive();
    });
  }
});
bindTeacherToggle(radioactive.controls.teacher, radioactive.teacherPanel);
bindLearningToggle(radioactive.controls.learning, "radioactive");

safeAddEventListener(radioactive.reset, "click", () => {
  Object.entries(radioactive.defaults).forEach(([key, value]) => {
    if (key === "labels") {
      radioactive.controls.labels.checked = value;
    } else if (key === "teacher") {
      radioactive.controls.teacher.checked = value;
    } else if (key === "learning") {
      radioactive.controls.learning.checked = value;
    } else if (key === "material") {
      radioactive.controls.material.value = value;
    } else {
      radioactive.controls[key].value = value;
    }
  });
  Object.entries(radioactive.values).forEach(([key, output]) => {
    output.textContent = radioactive.controls[key].value;
  });
  if (radioactive.values.material) {
    const selected =
      radioactive.controls.material.options[radioactive.controls.material.selectedIndex]?.text ||
      radioactive.controls.material.value;
    radioactive.values.material.textContent = selected;
  }
  updateLearningVisibility(radioactive.controls.learning, "radioactive");
  drawRadioactive();
});

