const getStandingStringVelocity = () => {
  const tension = parseFloat(standingStringSim.controls.tension.value);
  const linearDensity = 0.01;
  return Math.sqrt(tension / linearDensity);
};

const setStandingStringHarmonic = (harmonic) => {
  const length = parseFloat(standingStringSim.controls.length.value);
  const velocity = getStandingStringVelocity();
  const freq = clamp((harmonic * velocity) / (2 * length), 20, 500);
  standingStringSim.controls.freq.value = freq.toFixed(0);
  if (standingStringSim.values.freq) {
    standingStringSim.values.freq.textContent = standingStringSim.controls.freq.value;
  }
  drawStandingString();
};

