const getRutherfordScene = (width, height) => {
  const charge = parseFloat(rutherford.controls.nuclearCharge.value);
  const energy = parseFloat(rutherford.controls.alphaEnergy.value);
  const spread = parseFloat(rutherford.controls.beamSpread.value);
  const rate = parseFloat(rutherford.controls.particleRate.value);
  return {
    charge,
    energy,
    spread,
    rate,
    nucleus: {
      x: width * 0.62,
      y: height * 0.5,
      radius: 7 + ((charge - 40) / 52) * 7,
    },
    spreadPx: spread * 4,
    baseSpeed: 70 + energy * 18,
    k: 22000 * (charge / 79) / energy,
  };
};

const getMichelsonScene = (width, height) => {
  const wind = parseFloat(michelson.controls.etherWind.value);
  const armLength = parseFloat(michelson.controls.armLength.value);
  const rotation = (parseFloat(michelson.controls.rotation.value) * Math.PI) / 180;
  const contrast = parseFloat(michelson.controls.contrast.value);

  const center = { x: width * 0.38, y: height * 0.55 };
  const maxArm = Math.min(width, height) * 0.32;
  const arm = clamp(armLength * 9, 90, maxArm);

  const dirA = { x: Math.cos(rotation), y: Math.sin(rotation) };
  const dirB = { x: -Math.sin(rotation), y: Math.cos(rotation) };

  return {
    wind,
    armLength,
    rotation,
    contrast,
    center,
    arm,
    dirA,
    dirB,
    detector: {
      x: width * 0.78,
      y: height * 0.25,
      w: 26,
      h: height * 0.55,
    },
  };
};

safeAddEventListener(rutherford.canvas, "click", (event) => {
  const point = getCanvasPoint(rutherford.canvas, event);
  const width = rutherford.canvas.clientWidth;
  const height = rutherford.canvas.clientHeight;
  const scene = getRutherfordScene(width, height);
  const nucleus = scene.nucleus;

  const dx = point.x - nucleus.x;
  const dy = point.y - nucleus.y;
  const distance = Math.hypot(dx, dy);

  let message = "Thin gold foil region.";
  if (distance <= nucleus.radius + 3) {
    message = "Gold nucleus: dense, positively charged core.";
  } else {
    const particleHit = rutherford.state.particles.find(
      (particle) => Math.hypot(particle.x - point.x, particle.y - point.y) < 6
    );
    if (particleHit) {
      message = "Alpha particle in flight (scattered).";
    } else if (point.x < nucleus.x - 20 && Math.abs(point.y - nucleus.y) < scene.spreadPx) {
      message = "Incoming alpha particle beam.";
    } else if (point.x > nucleus.x + 20) {
      message = "Scattered particle region.";
    }
  }

  showTooltip(rutherford.tooltip, message, point.x, point.y);
});

safeAddEventListener(rutherford.canvas, "mouseleave", () => hideTooltip(rutherford.tooltip));

safeAddEventListener(michelson.canvas, "click", (event) => {
  const point = getCanvasPoint(michelson.canvas, event);
  const width = michelson.canvas.clientWidth;
  const height = michelson.canvas.clientHeight;
  const scene = getMichelsonScene(width, height);

  const center = scene.center;
  const arm = scene.arm;
  const dirA = scene.dirA;
  const dirB = scene.dirB;
  const detector = scene.detector;
  const mirrorSize = 12;
  const splitterSize = 12;

  const mirrorA = {
    x: center.x + dirA.x * arm - mirrorSize / 2,
    y: center.y + dirA.y * arm - mirrorSize / 2,
    w: mirrorSize,
    h: mirrorSize,
  };
  const mirrorB = {
    x: center.x + dirB.x * arm - mirrorSize / 2,
    y: center.y + dirB.y * arm - mirrorSize / 2,
    w: mirrorSize,
    h: mirrorSize,
  };
  const splitter = {
    x: center.x - splitterSize / 2,
    y: center.y - splitterSize / 2,
    w: splitterSize,
    h: splitterSize,
  };

  const insideRect = (rect) =>
    point.x >= rect.x &&
    point.x <= rect.x + rect.w &&
    point.y >= rect.y &&
    point.y <= rect.y + rect.h;

  let message = "Optical path region.";
  if (insideRect(splitter)) {
    message = "Beam splitter: divides the light into two paths.";
  } else if (insideRect(mirrorA) || insideRect(mirrorB)) {
    message = "Mirror: reflects the beam back to the splitter.";
  } else if (insideRect(detector)) {
    message = "Detector: interference fringes are measured here.";
  } else {
    const armAStart = center;
    const armAEnd = { x: center.x + dirA.x * arm, y: center.y + dirA.y * arm };
    const armBStart = center;
    const armBEnd = { x: center.x + dirB.x * arm, y: center.y + dirB.y * arm };
    const distanceA = distanceToSegment(point.x, point.y, armAStart.x, armAStart.y, armAEnd.x, armAEnd.y);
    const distanceB = distanceToSegment(point.x, point.y, armBStart.x, armBStart.y, armBEnd.x, armBEnd.y);
    if (Math.min(distanceA, distanceB) < 8) {
      message = "Interferometer arm: light travels down this path.";
    }
  }

  showTooltip(michelson.tooltip, message, point.x, point.y);
});

safeAddEventListener(michelson.canvas, "mouseleave", () => hideTooltip(michelson.tooltip));

if (freefall.canvas) {
  safeAddEventListener(freefall.canvas, "click", () => {
    if (!freefall.state.falling || freefall.state.landed) {
      freefall.state.y = 0;
      freefall.state.v = 0;
      freefall.state.time = 0;
      freefall.state.falling = true;
      freefall.state.landed = false;
    }
  });
}

const updateRutherford = (dt) => {
  const width = rutherford.canvas.clientWidth;
  const height = rutherford.canvas.clientHeight;
  const ctx = rutherford.ctx;
  ctx.clearRect(0, 0, width, height);

  const scene = getRutherfordScene(width, height);
  const nucleus = scene.nucleus;

  ctx.strokeStyle = "rgba(247, 200, 115, 0.35)";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(nucleus.x - 12, 20);
  ctx.lineTo(nucleus.x - 12, height - 20);
  ctx.stroke();

  ctx.fillStyle = "rgba(247, 200, 115, 0.85)";
  ctx.beginPath();
  ctx.arc(nucleus.x, nucleus.y, nucleus.radius, 0, Math.PI * 2);
  ctx.fill();

  ctx.strokeStyle = "rgba(247, 200, 115, 0.2)";
  ctx.beginPath();
  ctx.arc(nucleus.x, nucleus.y, nucleus.radius * 2.5, 0, Math.PI * 2);
  ctx.stroke();

  rutherford.state.spawnAccumulator += dt * scene.rate;
  while (rutherford.state.spawnAccumulator >= 1) {
    rutherford.state.spawnAccumulator -= 1;
    rutherford.state.particles.push({
      x: -20,
      y: nucleus.y + (Math.random() - 0.5) * scene.spreadPx * 2,
      vx: scene.baseSpeed,
      vy: (Math.random() - 0.5) * 6,
      deflection: null,
    });
  }

  const particles = [];
  rutherford.state.particles.forEach((particle) => {
    const dx = particle.x - nucleus.x;
    const dy = particle.y - nucleus.y;
    const r2 = Math.max(dx * dx + dy * dy, 120);
    const r = Math.sqrt(r2);
    const force = scene.k / r2;
    const ax = (dx / r) * force;
    const ay = (dy / r) * force;

    particle.vx += ax * dt;
    particle.vy += ay * dt;
    particle.x += particle.vx * dt;
    particle.y += particle.vy * dt;

    if (!particle.deflection && particle.x > nucleus.x + 20) {
      particle.deflection = Math.atan2(particle.vy, particle.vx);
      rutherford.state.deflections.push(particle.deflection);
      if (rutherford.state.deflections.length > 140) {
        rutherford.state.deflections.shift();
      }
    }

    const inBounds =
      particle.x > -40 &&
      particle.x < width + 40 &&
      particle.y > -40 &&
      particle.y < height + 40;

    if (inBounds) {
      particles.push(particle);
      ctx.fillStyle = "rgba(105, 209, 255, 0.9)";
      ctx.beginPath();
      ctx.arc(particle.x, particle.y, 2, 0, Math.PI * 2);
      ctx.fill();
    }
  });
  rutherford.state.particles = particles;

  const deflections = rutherford.state.deflections;
  const count = deflections.length;
  let avg = 0;
  let large = 0;
  deflections.forEach((angle) => {
    const degrees = Math.abs(angle) * (180 / Math.PI);
    avg += degrees;
    if (degrees > 20) {
      large += 1;
    }
  });
  avg = count ? avg / count : 0;

  rutherford.readout.innerHTML = [
    `<span>Avg scatter: ${avg.toFixed(1)}°</span>`,
    `<span>Large angle: ${count ? Math.round((large / count) * 100) : 0}%</span>`,
    `<span>Beam spread: ${scene.spread} mm</span>`,
  ].join("");

  if (rutherford.controls.labels.checked) {
    drawCallout(
      ctx,
      "Incoming beam",
      14,
      nucleus.y - scene.spreadPx - 40,
      40,
      nucleus.y - scene.spreadPx + 6,
      "left"
    );
    drawCallout(
      ctx,
      "Gold nucleus",
      nucleus.x + 20,
      nucleus.y - nucleus.radius - 36,
      nucleus.x,
      nucleus.y - nucleus.radius + 2,
      "left"
    );
    drawCallout(
      ctx,
      "Scattered region",
      width - 180,
      nucleus.y - scene.spreadPx - 40,
      width - 40,
      nucleus.y - scene.spreadPx + 6,
      "left"
    );
  }
};

const updateMichelson = (time) => {
  const width = michelson.canvas.clientWidth;
  const height = michelson.canvas.clientHeight;
  const ctx = michelson.ctx;
  ctx.clearRect(0, 0, width, height);

  const scene = getMichelsonScene(width, height);
  const center = scene.center;
  const arm = scene.arm;
  const dirA = scene.dirA;
  const dirB = scene.dirB;

  ctx.strokeStyle = "rgba(105, 209, 255, 0.35)";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(center.x, center.y);
  ctx.lineTo(center.x + dirA.x * arm, center.y + dirA.y * arm);
  ctx.moveTo(center.x, center.y);
  ctx.lineTo(center.x + dirB.x * arm, center.y + dirB.y * arm);
  ctx.stroke();

  const mirrorSize = 12;
  ctx.fillStyle = "rgba(255, 255, 255, 0.6)";
  ctx.fillRect(
    center.x + dirA.x * arm - mirrorSize / 2,
    center.y + dirA.y * arm - mirrorSize / 2,
    mirrorSize,
    mirrorSize
  );
  ctx.fillRect(
    center.x + dirB.x * arm - mirrorSize / 2,
    center.y + dirB.y * arm - mirrorSize / 2,
    mirrorSize,
    mirrorSize
  );

  ctx.fillStyle = "rgba(105, 209, 255, 0.9)";
  ctx.fillRect(center.x - 6, center.y - 6, 12, 12);

  const v = scene.wind * 0.7;
  const tA = (2 * scene.armLength) / (1 - Math.pow(v * dirA.x, 2));
  const tB = (2 * scene.armLength) / (1 - Math.pow(v * dirB.x, 2));
  const delta = tA - tB;
  const fringeShift = delta * 4;

  const detector = scene.detector;

  ctx.save();
  ctx.translate(detector.x, detector.y);
  const period = 18;
  for (let y = 0; y < detector.h; y += 1) {
    const intensity =
      0.5 + 0.5 * Math.cos((y / period) * Math.PI * 2 + fringeShift);
    const alpha = 0.15 + intensity * 0.55 * scene.contrast;
    ctx.fillStyle = `rgba(105, 209, 255, ${alpha})`;
    ctx.fillRect(0, y, detector.w, 1);
  }
  ctx.restore();

  ctx.strokeStyle = "rgba(255, 255, 255, 0.35)";
  ctx.strokeRect(detector.x, detector.y, detector.w, detector.h);

  const pulseSpeed = 0.6;
  const cycle = (time * pulseSpeed) % 2;
  const progress = cycle <= 1 ? cycle : 2 - cycle;
  const offset = ((time * pulseSpeed + 0.35) % 2);
  const progressB = offset <= 1 ? offset : 2 - offset;

  ctx.fillStyle = "rgba(247, 200, 115, 0.95)";
  ctx.beginPath();
  ctx.arc(
    center.x + dirA.x * arm * progress,
    center.y + dirA.y * arm * progress,
    4,
    0,
    Math.PI * 2
  );
  ctx.fill();

  ctx.beginPath();
  ctx.arc(
    center.x + dirB.x * arm * progressB,
    center.y + dirB.y * arm * progressB,
    4,
    0,
    Math.PI * 2
  );
  ctx.fill();

  michelson.readout.innerHTML = [
    `<span>Predicted fringe shift: ${fringeShift.toFixed(2)}</span>`,
    `<span>Δt (relative): ${delta.toFixed(2)}</span>`,
    `<span>v/c: ${v.toFixed(2)}</span>`,
  ].join("");

  if (michelson.controls.labels.checked) {
    drawCallout(
      ctx,
      "Beam splitter",
      center.x - 80,
      center.y + 18,
      center.x,
      center.y,
      "left"
    );
    drawCallout(
      ctx,
      "Mirror A",
      center.x + dirA.x * arm + 18,
      center.y + dirA.y * arm - 30,
      center.x + dirA.x * arm,
      center.y + dirA.y * arm,
      "left"
    );
    drawCallout(
      ctx,
      "Mirror B",
      center.x + dirB.x * arm + 18,
      center.y + dirB.y * arm - 30,
      center.x + dirB.x * arm,
      center.y + dirB.y * arm,
      "left"
    );
    drawCallout(
      ctx,
      "Detector",
      detector.x - 90,
      detector.y - 18,
      detector.x + detector.w / 2,
      detector.y + detector.h / 2,
      "left"
    );
  }
};

