const iconForExperiment = (exp, index = 0) => {
  const pool = iconMap[exp.category] || iconMap.other;
  const seed = (exp.name || '').split('').reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
  return pool[(seed + index) % pool.length];
};

const durationForExperiment = (exp) => {
  const base = 12 + (exp.name.length % 10);
  return `${base} min`;
};

const RECENT_SIM_KEY = 'recentSimulations';
const getRecentSimulations = () => {
  try {
    return JSON.parse(localStorage.getItem(RECENT_SIM_KEY) || '[]');
  } catch {
    return [];
  }
};

const saveRecentSimulation = (id) => {
  if (!id) return;
  let recent = getRecentSimulations();
  recent = recent.filter(item => item !== id);
  recent.unshift(id);
  recent = recent.slice(0, 8);
  localStorage.setItem(RECENT_SIM_KEY, JSON.stringify(recent));
};

const renderRecentSimulations = () => {
  const containers = document.querySelectorAll('[data-recent-sims]');
  if (!containers.length) return;
  const recent = getRecentSimulations();
  containers.forEach(container => {
    if (recent.length === 0) {
      container.innerHTML = '<p class="no-favorites">No recent simulations yet.</p>';
      return;
    }
    const cards = recent.map((id, idx) => {
      const exp = experimentData.find(item => item.id === id);
      if (!exp) return '';
      const icon = iconForExperiment(exp, idx);
      const tags = (exp.tags || []).slice(0, 3).map(t => `#${t}`).join(' ');
      return `
        <div class="sim-card">
          <div class="sim-card-top">${icon}</div>
          <div class="sim-card-body">
            <h3>${exp.name}</h3>
            <p>${exp.desc}</p>
            <div class="sim-tags">
              <span class="tag category">${(exp.category || 'other').replace(/-/g, ' ')}</span>
            </div>
            <div class="sim-meta">⏱ ${durationForExperiment(exp)}</div>
            <div style="color: rgba(125, 211, 252, 0.6); font-size: 12px;">${tags}</div>
            <a href="simulations/${exp.id}.html">Open Solo View</a>
          </div>
        </div>
      `;
    }).join('');
    container.innerHTML = cards;
  });
};

window.EXPERIMENTS = experimentData;

