/* === SHARED VISUAL EFFECTS (Phase 2) === */

/**
 * Shared Visual Effects for All Simulations
 */
const VisualEffects = {
  // Create glowing point effect
  drawGlowPoint(ctx, x, y, radius, color, glowRadius = 20) {
    const gradient = ctx.createRadialGradient(x, y, 0, x, y, glowRadius);
    gradient.addColorStop(0, color);
    gradient.addColorStop(0.5, color.replace('1)', '0.3)'));
    gradient.addColorStop(1, 'rgba(0,0,0,0)');
    
    ctx.fillStyle = gradient;
    ctx.beginPath();
    ctx.arc(x, y, glowRadius, 0, Math.PI * 2);
    ctx.fill();
    
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(x, y, radius, 0, Math.PI * 2);
    ctx.fill();
  },
  
  // Draw gradient curve fill
  drawGradientCurve(ctx, points, x1, y1, x2, y2, color = 'rgba(97, 196, 255, 0.3)') {
    const gradient = ctx.createLinearGradient(x1, y1, x2, y2);
    gradient.addColorStop(0, color);
    gradient.addColorStop(1, 'rgba(0,0,0,0)');
    
    ctx.fillStyle = gradient;
    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);
    
    for (let i = 1; i < points.length; i++) {
      ctx.lineTo(points[i].x, points[i].y);
    }
    
    ctx.lineTo(points[points.length - 1].x, ctx.canvas.height);
    ctx.lineTo(points[0].x, ctx.canvas.height);
    ctx.closePath();
    ctx.fill();
  },
  
  // Draw FWHM markers
  drawFWHMMarkers(ctx, centerX, halfMax, fwhm, scaleX, scaleY, height) {
    const leftX = scaleX(centerX - fwhm / 2);
    const rightX = scaleX(centerX + fwhm / 2);
    const halfY = scaleY(halfMax);
    
    ctx.strokeStyle = 'rgba(251, 191, 36, 0.8)';
    ctx.setLineDash([6, 4]);
    ctx.lineWidth = 2;
    
    // Left marker
    ctx.beginPath();
    ctx.moveTo(leftX, halfY);
    ctx.lineTo(leftX, height);
    ctx.stroke();
    
    // Right marker
    ctx.beginPath();
    ctx.moveTo(rightX, halfY);
    ctx.lineTo(rightX, height);
    ctx.stroke();
    
    // FWHM line
    ctx.beginPath();
    ctx.moveTo(leftX, halfY);
    ctx.lineTo(rightX, halfY);
    ctx.stroke();
    
    ctx.setLineDash([]);
    
    // Label
    ctx.fillStyle = '#fbbf24';
    ctx.font = 'bold 12px "Space Grotesk", sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('FWHM', (leftX + rightX) / 2, halfY - 10);
  },
  
  // Setup canvas tooltip
  setupCanvasTooltip(canvasId) {
    const canvas = document.getElementById(canvasId);
    const tooltip = document.getElementById(canvasId.replace('Canvas', 'Tooltip'));
    
    if (!canvas || !tooltip) return null;
    
    return {
      show: (x, y, text) => {
        tooltip.textContent = text;
        tooltip.style.left = x + 'px';
        tooltip.style.top = y + 'px';
        tooltip.classList.add('visible');
      },
      hide: () => {
        tooltip.classList.remove('visible');
      }
    };
  },
  
  // Animate particles with glow
  animateParticle(ctx, particle, baseRadius) {
    const time = Date.now() / 1000;
    const pulse = Math.sin(time * 3 + particle.phase) * 0.3 + 1;
    const radius = baseRadius * pulse;
    
    VisualEffects.drawGlowPoint(
      ctx, 
      particle.x, 
      particle.y, 
      radius, 
      particle.color,
      radius * 3
    );
  }
};

// Auto-initialize visual effects
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.lab-canvas').forEach(canvas => {
    const tooltipId = canvas.id.replace('Canvas', 'Tooltip');
    const tooltip = document.getElementById(tooltipId);
    
    if (tooltip) {
      canvas.addEventListener('mousemove', (e) => {
        const rect = canvas.getBoundingClientRect();
        tooltip.style.left = (e.clientX - rect.left + 10) + 'px';
        tooltip.style.top = (e.clientY - rect.top - 30) + 'px';
      });
      
      canvas.addEventListener('mouseleave', () => {
        tooltip.classList.remove('visible');
      });
    }
  });
});


/* === INTERACTION UTILITIES (Phase 3) === */

/**
 * Touch & Interaction Utilities (Phase 3)
 */
const InteractionUtils = {
  // Pinch-to-zoom state
  pinchState: {
    active: false,
    startDistance: 0,
    currentScale: 1
  },
  
  // Pan state
  panState: {
    active: false,
    startX: 0,
    startY: 0,
    offsetX: 0,
    offsetY: 0
  },
  
  // Setup pinch-to-zoom for canvas
  setupPinchZoom(canvas, onZoom) {
    canvas.addEventListener('touchstart', (e) => {
      if (e.touches.length === 2) {
        e.preventDefault();
        const touch1 = e.touches[0];
        const touch2 = e.touches[1];
        const distance = Math.hypot(
          touch2.clientX - touch1.clientX,
          touch2.clientY - touch1.clientY
        );
        InteractionUtils.pinchState = {
          active: true,
          startDistance: distance,
          currentScale: 1
        };
      }
    }, { passive: false });
    
    canvas.addEventListener('touchmove', (e) => {
      if (InteractionUtils.pinchState.active && e.touches.length === 2) {
        e.preventDefault();
        const touch1 = e.touches[0];
        const touch2 = e.touches[1];
        const distance = Math.hypot(
          touch2.clientX - touch1.clientX,
          touch2.clientY - touch1.clientY
        );
        const scale = distance / InteractionUtils.pinchState.startDistance;
        InteractionUtils.pinchState.currentScale = scale;
        
        if (onZoom) {
          onZoom(Math.min(Math.max(scale, 0.5), 3));
        }
      }
    }, { passive: false });
    
    canvas.addEventListener('touchend', () => {
      InteractionUtils.pinchState.active = false;
      InteractionUtils.pinchState.currentScale = 1;
    });
  },
  
  // Setup drag-to-pan for canvas
  setupDragPan(canvas, onPan) {
    let isDragging = false;
    let startX, startY;
    
    canvas.addEventListener('mousedown', (e) => {
      if (e.button === 0) {
        isDragging = true;
        startX = e.clientX;
        startY = e.clientY;
        canvas.classList.add('pannable');
      }
    });
    
    canvas.addEventListener('mousemove', (e) => {
      if (isDragging) {
        const dx = e.clientX - startX;
        const dy = e.clientY - startY;
        startX = e.clientX;
        startY = e.clientY;
        
        InteractionUtils.panState.offsetX += dx;
        InteractionUtils.panState.offsetY += dy;
        
        if (onPan) {
          onPan(InteractionUtils.panState.offsetX, InteractionUtils.panState.offsetY);
        }
      }
    });
    
    canvas.addEventListener('mouseup', () => {
      isDragging = false;
      canvas.classList.remove('pannable');
    });
    
    canvas.addEventListener('mouseleave', () => {
      isDragging = false;
      canvas.classList.remove('pannable');
    });
    
    // Touch pan
    canvas.addEventListener('touchstart', (e) => {
      if (e.touches.length === 1 && !InteractionUtils.pinchState.active) {
        isDragging = true;
        startX = e.touches[0].clientX;
        startY = e.touches[0].clientY;
      }
    }, { passive: true });
    
    canvas.addEventListener('touchmove', (e) => {
      if (isDragging && e.touches.length === 1) {
        const dx = e.touches[0].clientX - startX;
        const dy = e.touches[0].clientY - startY;
        startX = e.touches[0].clientX;
        startY = e.touches[0].clientY;
        
        InteractionUtils.panState.offsetX += dx;
        InteractionUtils.panState.offsetY += dy;
        
        if (onPan) {
          onPan(InteractionUtils.panState.offsetX, InteractionUtils.panState.offsetY);
        }
      }
    }, { passive: true });
    
    canvas.addEventListener('touchend', () => {
      isDragging = false;
    });
  },
  
  // Reset pan/zoom state
  resetPanZoom() {
    InteractionUtils.panState = {
      active: false,
      startX: 0,
      startY: 0,
      offsetX: 0,
      offsetY: 0
    };
    InteractionUtils.pinchState = {
      active: false,
      startDistance: 0,
      currentScale: 1
    };
  },
  
  // Setup keyboard shortcuts for accessibility
  setupKeyboardControls(canvas, actions) {
    canvas.setAttribute('tabindex', '0');
    canvas.setAttribute('role', 'application');
    
    canvas.addEventListener('keydown', (e) => {
      const step = e.shiftKey ? 10 : 1;
      
      switch(e.key) {
        case 'ArrowUp':
          e.preventDefault();
          if (actions.onVertical) actions.onVertical(step);
          break;
        case 'ArrowDown':
          e.preventDefault();
          if (actions.onVertical) actions.onVertical(-step);
          break;
        case 'ArrowLeft':
          e.preventDefault();
          if (actions.onHorizontal) actions.onHorizontal(-step);
          break;
        case 'ArrowRight':
          e.preventDefault();
          if (actions.onHorizontal) actions.onHorizontal(step);
          break;
        case 'r':
        case 'R':
          if (actions.onReset) actions.onReset();
          break;
        case ' ':
          e.preventDefault();
          if (actions.onPlayPause) actions.onPlayPause();
          break;
      }
    });
  },
  
  // Long press detection
  setupLongPress(element, callback, duration = 500) {
    let timer;
    
    element.addEventListener('touchstart', () => {
      timer = setTimeout(() => {
        callback();
        element.classList.add('long-press');
      }, duration);
    });
    
    element.addEventListener('touchend', () => {
      clearTimeout(timer);
      element.classList.remove('long-press');
    });
    
    element.addEventListener('touchcancel', () => {
      clearTimeout(timer);
      element.classList.remove('long-press');
    });
  }
};

// Auto-initialize interaction features
document.addEventListener('DOMContentLoaded', () => {
  // Add zoomable class to canvases that support it
  document.querySelectorAll('.lab-canvas[data-zoomable="true"]').forEach(canvas => {
    canvas.classList.add('zoomable');
    InteractionUtils.setupPinchZoom(canvas, (scale) => {
      canvas.style.transform = `scale(${scale})`;
    });
  });
  
  // Add pannable class to canvases that support panning
  document.querySelectorAll('.lab-canvas[data-pannable="true"]').forEach(canvas => {
    canvas.classList.add('pannable');
    InteractionUtils.setupDragPan(canvas, (x, y) => {
      // Override in specific simulations as needed
    });
  });
  
  // Setup long press on reset buttons
  document.querySelectorAll('.lab .btn.ghost[id$="Reset"]').forEach(btn => {
    InteractionUtils.setupLongPress(btn, () => {
      btn.style.transform = 'scale(0.95)';
      btn.click();
      setTimeout(() => {
        btn.style.transform = '';
      }, 200);
    });
  });
});


/* === CORE ENGINE IMPROVEMENTS (Phase 4) === */

/**
 * Base Simulation Class (Phase 4)
 * Provides common functionality for all simulations
 */
class BaseSimulation {
  constructor(canvasId, options = {}) {
    this.canvas = document.getElementById(canvasId);
    if (!this.canvas) {
      console.warn(`Canvas ${canvasId} not found`);
      return;
    }
    
    this.ctx = this.canvas.getContext('2d');
    this.options = {
      dprCap: options.dprCap || 2,
      particleScale: options.particleScale || 1,
      autoResize: options.autoResize !== false,
      ...options
    };
    
    this.width = 0;
    this.height = 0;
    this.dpr = 1;
    this.isRunning = false;
    this.animationId = null;
    this.lastFrameTime = 0;
    this.fps = 60;
    this.particles = [];
    this.tooltip = null;
    
    this.init();
  }
  
  init() {
    this.setupCanvas();
    this.setupControls();
    this.setupEventListeners();
    
    if (this.options.autoResize) {
      this.handleResize();
    }
  }
  
  setupCanvas() {
    this.handleResize();
    
    const resizeObserver = new ResizeObserver(() => {
      this.handleResize();
    });
    resizeObserver.observe(this.canvas.parentElement);
  }
  
  handleResize() {
    const rect = this.canvas.getBoundingClientRect();
    this.dpr = Math.min(window.devicePixelRatio || 1, this.options.dprCap);
    
    this.width = rect.width;
    this.height = rect.height;
    
    this.canvas.width = this.width * this.dpr;
    this.canvas.height = this.height * this.dpr;
    
    this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);
    
    if (this.onResize) {
      this.onResize();
    }
  }
  
  setupControls() {
    // Override in subclass
  }
  
  setupEventListeners() {
    // Mouse events
    this.canvas.addEventListener('mousemove', (e) => this.onMouseMove(e));
    this.canvas.addEventListener('mousedown', (e) => this.onMouseDown(e));
    this.canvas.addEventListener('mouseup', (e) => this.onMouseUp(e));
    this.canvas.addEventListener('mouseleave', () => this.onMouseLeave());
    
    // Touch events
    this.canvas.addEventListener('touchstart', (e) => this.onTouchStart(e), { passive: false });
    this.canvas.addEventListener('touchmove', (e) => this.onTouchMove(e), { passive: false });
    this.canvas.addEventListener('touchend', () => this.onTouchEnd());
    
    // Keyboard
    if (this.canvas) {
      this.canvas.setAttribute('tabindex', '0');
      this.canvas.addEventListener('keydown', (e) => this.onKeyDown(e));
    }
  }
  
  // Event handlers (override in subclass)
  onMouseMove(e) {}
  onMouseDown(e) {}
  onMouseUp(e) {}
  onMouseLeave() {}
  onTouchStart(e) {}
  onTouchMove(e) {}
  onTouchEnd() {}
  onKeyDown(e) {}
  onResize() {}
  
  // Animation loop
  start() {
    if (this.isRunning) return;
    this.isRunning = true;
    this.lastFrameTime = performance.now();
    this.tick();
  }
  
  stop() {
    this.isRunning = false;
    if (this.animationId) {
      cancelAnimationFrame(this.animationId);
      this.animationId = null;
    }
  }
  
  toggle() {
    if (this.isRunning) {
      this.stop();
    } else {
      this.start();
    }
  }
  
  tick() {
    if (!this.isRunning) return;
    
    const now = performance.now();
    const delta = now - this.lastFrameTime;
    this.lastFrameTime = now;
    this.fps = 1000 / delta;
    
    this.update(delta);
    this.render();
    
    this.animationId = requestAnimationFrame(() => this.tick());
  }
  
  update(delta) {
    // Override in subclass
  }
  
  render() {
    // Override in subclass
  }
  
  // Utility methods
  clear(color = 'rgba(8, 12, 22, 1)') {
    this.ctx.fillStyle = color;
    this.ctx.fillRect(0, 0, this.width, this.height);
  }
  
  drawPoint(x, y, radius, color, glow = true) {
    if (glow) {
      const gradient = this.ctx.createRadialGradient(x, y, 0, x, y, radius * 3);
      gradient.addColorStop(0, color);
      gradient.addColorStop(1, 'rgba(0,0,0,0)');
      this.ctx.fillStyle = gradient;
      this.ctx.beginPath();
      this.ctx.arc(x, y, radius * 3, 0, Math.PI * 2);
      this.ctx.fill();
    }
    
    this.ctx.fillStyle = color;
    this.ctx.beginPath();
    this.ctx.arc(x, y, radius, 0, Math.PI * 2);
    this.ctx.fill();
  }
  
  drawLine(x1, y1, x2, y2, color, width = 2) {
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = width;
    this.ctx.lineCap = 'round';
    this.ctx.beginPath();
    this.ctx.moveTo(x1, y1);
    this.ctx.lineTo(x2, y2);
    this.ctx.stroke();
  }
  
  drawArrow(x1, y1, x2, y2, color, headLen = 10) {
    const angle = Math.atan2(y2 - y1, x2 - x1);
    
    this.drawLine(x1, y1, x2, y2, color);
    
    this.ctx.fillStyle = color;
    this.ctx.beginPath();
    this.ctx.moveTo(x2, y2);
    this.ctx.lineTo(
      x2 - headLen * Math.cos(angle - Math.PI / 6),
      y2 - headLen * Math.sin(angle - Math.PI / 6)
    );
    this.ctx.lineTo(
      x2 - headLen * Math.cos(angle + Math.PI / 6),
      y2 - headLen * Math.sin(angle + Math.PI / 6)
    );
    this.ctx.closePath();
    this.ctx.fill();
  }
  
  drawText(text, x, y, options = {}) {
    const {
      font = '14px "IBM Plex Sans", sans-serif',
      color = '#e0f0ff',
      align = 'left',
      baseline = 'top',
      shadow = true
    } = options;
    
    this.ctx.font = font;
    this.ctx.textAlign = align;
    this.ctx.textBaseline = baseline;
    
    if (shadow) {
      this.ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
      this.ctx.shadowBlur = 4;
      this.ctx.shadowOffsetX = 2;
      this.ctx.shadowOffsetY = 2;
    }
    
    this.ctx.fillStyle = color;
    this.ctx.fillText(text, x, y);
    
    this.ctx.shadowColor = 'transparent';
  }
  
  drawRect(x, y, w, h, fill, stroke = null) {
    if (fill) {
      this.ctx.fillStyle = fill;
      this.ctx.fillRect(x, y, w, h);
    }
    if (stroke) {
      this.ctx.strokeStyle = stroke;
      this.ctx.lineWidth = 1;
      this.ctx.strokeRect(x, y, w, h);
    }
  }
  
  drawCircle(x, y, r, fill, stroke = null) {
    this.ctx.beginPath();
    this.ctx.arc(x, y, r, 0, Math.PI * 2);
    
    if (fill) {
      this.ctx.fillStyle = fill;
      this.ctx.fill();
    }
    if (stroke) {
      this.ctx.strokeStyle = stroke;
      this.ctx.lineWidth = 1;
      this.ctx.stroke();
    }
  }
  
  drawGradientRect(x, y, w, h, colors, vertical = true) {
    const gradient = vertical
      ? this.ctx.createLinearGradient(x, y, x, y + h)
      : this.ctx.createLinearGradient(x, y, x + w, y);
    
    colors.forEach((color, i) => {
      gradient.addColorStop(i / (colors.length - 1), color);
    });
    
    this.ctx.fillStyle = gradient;
    this.ctx.fillRect(x, y, w, h);
  }
  
  // Particle system
  createParticle(x, y, options = {}) {
    return {
      x, y,
      vx: options.vx || (Math.random() - 0.5) * 2,
      vy: options.vy || (Math.random() - 0.5) * 2,
      radius: options.radius || 3 * this.options.particleScale,
      color: options.color || 'rgba(100, 200, 255, 1)',
      life: options.life || 1,
      decay: options.decay || 0.01,
      gravity: options.gravity || 0,
      friction: options.friction || 0.99
    };
  }
  
  addParticle(x, y, options) {
    this.particles.push(this.createParticle(x, y, options));
  }
  
  updateParticles() {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      
      p.x += p.vx;
      p.y += p.vy;
      p.vy += p.gravity;
      p.vx *= p.friction;
      p.vy *= p.friction;
      p.life -= p.decay;
      
      if (p.life <= 0) {
        this.particles.splice(i, 1);
      }
    }
  }
  
  drawParticles() {
    this.particles.forEach(p => {
      this.drawPoint(p.x, p.y, p.radius * p.life, p.color);
    });
  }
  
  // Tooltip
  showTooltip(x, y, text) {
    if (!this.tooltip) {
      this.tooltip = document.createElement('div');
      this.tooltip.className = 'canvas-tooltip';
      this.canvas.parentElement.appendChild(this.tooltip);
    }
    
    this.tooltip.textContent = text;
    this.tooltip.style.left = (x + 10) + 'px';
    this.tooltip.style.top = (y - 30) + 'px';
    this.tooltip.classList.add('visible');
  }
  
  hideTooltip() {
    if (this.tooltip) {
      this.tooltip.classList.remove('visible');
    }
  }
  
  // Cleanup
  destroy() {
    this.stop();
    this.particles = [];
  }
}

// Make available globally
window.BaseSimulation = BaseSimulation;

/**
 * Performance monitoring
 */
const PerformanceMonitor = {
  samples: [],
  maxSamples: 60,
  
  record(fps) {
    this.samples.push(fps);
    if (this.samples.length > this.maxSamples) {
      this.samples.shift();
    }
  },
  
  getAverage() {
    if (this.samples.length === 0) return 60;
    return this.samples.reduce((a, b) => a + b, 0) / this.samples.length;
  },
  
  getStatus() {
    const avg = this.getAverage();
    if (avg >= 55) return 'excellent';
    if (avg >= 30) return 'good';
    if (avg >= 15) return 'fair';
    return 'poor';
  }
};

/**
 * Optimized resize handler (debounced)
 */
const debounce = (fn, delay) => {
  let timeoutId;
  return (...args) => {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn(...args), delay);
  };
};

/**
 * Lazy canvas rendering (only render when visible)
 */
const LazyCanvasRenderer = {
  observer: null,
  canvases: new Map(),
  
  init() {
    this.observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        const canvas = entry.target;
        const renderer = this.canvases.get(canvas);
        
        if (renderer) {
          renderer.isVisible = entry.isIntersecting;
          
          if (entry.isIntersecting && renderer.isRunning) {
            renderer.start();
          } else {
            renderer.stop();
          }
        }
      });
    }, { threshold: 0.1 });
  },
  
  register(canvas, renderer) {
    if (!this.observer) this.init();
    
    this.canvases.set(canvas, renderer);
    this.observer.observe(canvas);
  }
};


/* === EDUCATIONAL & PERFORMANCE (Phase 5 & 6) === */

/**
 * Performance Optimization Utilities (Phase 6)
 */

// Performance-aware rendering
const PerformanceAwareRenderer = {
  targetFPS: 60,
  minFPS: 30,
  
  shouldRender(fps) {
    return fps >= this.minFPS;
  },
  
  adjustQuality(fps) {
    if (fps < 30) return 'low';
    if (fps < 45) return 'medium';
    return 'high';
  }
};

// Frame rate independent animation
const FrameIndependentAnimation = {
  lastTime: 0,
  deltaTime: 0,
  
  update(timestamp) {
    this.deltaTime = timestamp - this.lastTime;
    this.lastTime = timestamp;
    return this.deltaTime;
  },
  
  // Normalize delta to target frame time
  normalize(delta) {
    return delta / (1000 / PerformanceAwareRenderer.targetFPS);
  }
};

// Request Animation Frame with fallback
const raf = window.requestAnimationFrame ||
            window.webkitRequestAnimationFrame ||
            function(callback) {
              setTimeout(callback, 1000 / 60);
            };

// Canvas rendering optimizations
const CanvasOptimizer = {
  // Use offscreen canvas for complex operations
  createOffscreenCanvas(width, height) {
    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    return canvas;
  },
  
  // Cache gradient patterns
  gradientCache: new Map(),
  
  getGradient(ctx, key, createFn) {
    if (!this.gradientCache.has(key)) {
      this.gradientCache.set(key, createFn(ctx));
    }
    return this.gradientCache.get(key);
  },
  
  clearCache() {
    this.gradientCache.clear();
  },
  
  // Batch drawing operations
  batchDraw(ctx, operations) {
    ctx.save();
    operations.forEach(op => {
      if (op.type === 'fill') {
        ctx.fillStyle = op.style;
        ctx.fillRect(op.x, op.y, op.w, op.h);
      } else if (op.type === 'stroke') {
        ctx.strokeStyle = op.style;
        ctx.lineWidth = op.lineWidth || 1;
        ctx.strokeRect(op.x, op.y, op.w, op.h);
      }
    });
    ctx.restore();
  }
};

// Memory management for particles
const ParticleManager = {
  maxParticles: 500,
  
  prune(particles) {
    if (particles.length > this.maxParticles) {
      return particles.slice(-this.maxParticles);
    }
    return particles;
  }
};

// Auto-adjust quality based on performance
const AdaptiveQuality = {
  currentQuality: 'high',
  fpsHistory: [],
  
  adjust(fps) {
    this.fpsHistory.push(fps);
    if (this.fpsHistory.length > 30) {
      this.fpsHistory.shift();
    }
    
    const avgFPS = this.fpsHistory.reduce((a, b) => a + b, 0) / this.fpsHistory.length;
    
    if (avgFPS < 25 && this.currentQuality !== 'low') {
      this.currentQuality = 'low';
      this.applyQuality();
    } else if (avgFPS < 40 && avgFPS >= 25 && this.currentQuality !== 'medium') {
      this.currentQuality = 'medium';
      this.applyQuality();
    } else if (avgFPS >= 50 && this.currentQuality !== 'high') {
      this.currentQuality = 'high';
      this.applyQuality();
    }
  },
  
  applyQuality() {
    const lab = document.querySelector('.lab-grid');
    if (lab) {
      lab.classList.remove('perf-high', 'perf-medium', 'perf-low');
      lab.classList.add(`perf-${this.currentQuality}`);
    }
    
    // Dispatch event for simulations to adjust
    window.dispatchEvent(new CustomEvent('qualitychange', {
      detail: { quality: this.currentQuality }
    }));
  }
};

// Initialize lazy loading for images
document.addEventListener('DOMContentLoaded', () => {
  const lazyImages = document.querySelectorAll('img[data-src]');
  
  if ('IntersectionObserver' in window) {
    const imageObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const img = entry.target;
          img.src = img.dataset.src;
          img.classList.add('loaded');
          imageObserver.unobserve(img);
        }
      });
    });
    
    lazyImages.forEach(img => imageObserver.observe(img));
  } else {
    // Fallback
    lazyImages.forEach(img => {
      img.src = img.dataset.src;
      img.classList.add('loaded');
    });
  }
  
  // Start performance monitoring
  setInterval(() => {
    if (window.performanceMonitor) {
      AdaptiveQuality.adjust(window.performanceMonitor.getAverage());
    }
  }, 2000);
});

// Decorate simulation category labels with matching icons
document.addEventListener('DOMContentLoaded', () => {
  const categoryIcons = {
    waves: '∿',
    optics: '◈',
    mechanics: '⟲',
    electricity: '⚡',
    thermal: '♨',
    fluids: '≈',
    quantum: '⧉',
    modern: '◇',
    communications: '⟋⟍',
    astrophysics: '✶',
    measurement: '⊟',
    medical: '✚',
    nuclear: '☢'
  };

  document.querySelectorAll('.sim-category').forEach((el) => {
    if (el.dataset.iconized === 'true') return;
    const raw = el.textContent.trim().toLowerCase();
    const key = Object.keys(categoryIcons).find((name) => raw.includes(name));
    if (!key) return;
    el.textContent = `${categoryIcons[key]} ${raw.toUpperCase()}`;
    el.dataset.iconized = 'true';
  });
});

// Export for use in simulations
window.CanvasOptimizer = CanvasOptimizer;
window.ParticleManager = ParticleManager;
window.AdaptiveQuality = AdaptiveQuality;
window.PerformanceAwareRenderer = PerformanceAwareRenderer;
